            let i = app
                .branch_list_state
                .selected()
                .map_or(0, |i| i.saturating_sub(1));
            app.branch_list_state.select(Some(i));
        }
        KeyCode::Enter => {
            if let Some(i) = app.branch_list_state.selected() {
                if let Some(branch) = app.branches.get(i) {
                    app.selected_branch = branch.clone();
                    let _ = app.cache.refresh().await;
                    app.clamp_selection();
                }
            }
            app.branch_popup_open = false;
        }
        KeyCode::Esc | KeyCode::Char('q') => {
            app.branch_popup_open = false;
        }
        _ => {}
    }
}

fn centered_rect(width: u16, height: u16, area: Rect) -> Rect {
    let x = area.x + (area.width.saturating_sub(width)) / 2;
    let y = area.y + (area.height.saturating_sub(height)) / 2;
    Rect::new(x, y, width.min(area.width), height.min(area.height))
}

