use std::io::Stdout;

use anyhow::Result;
use crossterm::event::{self, Event, KeyCode, KeyEvent, KeyModifiers};
use crossterm::execute;
use crossterm::terminal::{self, EnterAlternateScreen, LeaveAlternateScreen};
use mementor_lib::cache::DataCache;
use mementor_lib::git::branch::list_branches;
use ratatui::Terminal;
use ratatui::backend::CrosstermBackend;
use ratatui::prelude::*;
use ratatui::widgets::ListState;

use crate::views::{branch_popup, dashboard, status_bar};

pub enum View {
    CheckpointList,
}

pub struct App {
    pub view: View,
    pub cache: DataCache,
    pub list_state: ListState,
    pub selected_branch: String,
    pub running: bool,
    pub branch_popup_open: bool,
    pub branches: Vec<String>,
    pub branch_list_state: ListState,
}

impl App {
    pub fn new(cache: DataCache, branch: String) -> Self {
        let mut list_state = ListState::default();
        if !cache.checkpoints().is_empty() {
            list_state.select(Some(0));
        }
        Self {
            view: View::CheckpointList,
            cache,
            list_state,
            selected_branch: branch,
            running: true,
            branch_popup_open: false,
            branches: Vec::new(),
            branch_list_state: ListState::default(),
        }
    }

    pub fn setup_terminal() -> Result<Terminal<CrosstermBackend<Stdout>>> {
        terminal::enable_raw_mode()?;
        let mut stdout = std::io::stdout();
        execute!(stdout, EnterAlternateScreen)?;
        let backend = CrosstermBackend::new(stdout);
        let terminal = Terminal::new(backend)?;
        Ok(terminal)
    }

    pub fn restore_terminal(terminal: &mut Terminal<CrosstermBackend<Stdout>>) -> Result<()> {
        terminal::disable_raw_mode()?;
        execute!(terminal.backend_mut(), LeaveAlternateScreen)?;
        terminal.show_cursor()?;
        Ok(())
    }

    pub async fn run(&mut self, terminal: &mut Terminal<CrosstermBackend<Stdout>>) -> Result<()> {
        loop {
            terminal.draw(|frame| self.render(frame))?;

            if event::poll(std::time::Duration::from_millis(100))? {
                if let Event::Key(key) = event::read()? {
                    self.handle_key(key).await;
                }
            }

            if !self.running {
                break;
            }
        }
        Ok(())
    }

    fn render(&mut self, frame: &mut Frame) {
        let area = frame.area();

        let chunks = Layout::default()
            .direction(Direction::Vertical)
            .constraints([Constraint::Min(1), Constraint::Length(1)])
            .split(area);

        match self.view {
            View::CheckpointList => dashboard::render(frame, chunks[0], self),
        }
        status_bar::render(frame, chunks[1], self);

        if self.branch_popup_open {
            branch_popup::render(frame, area, self);
        }
    }

    async fn handle_key(&mut self, key: KeyEvent) {
        // Ctrl-c always quits.
        if key.modifiers.contains(KeyModifiers::CONTROL) && key.code == KeyCode::Char('c') {
            self.running = false;
            return;
        }

        if self.branch_popup_open {
            branch_popup::handle_key(key, self).await;
            return;
        }

        match self.view {
            View::CheckpointList => self.handle_dashboard_key(key).await,
        }
    }

    async fn handle_dashboard_key(&mut self, key: KeyEvent) {
        match key.code {
            KeyCode::Char('q') => self.running = false,
            KeyCode::Char('j') | KeyCode::Down => self.select_next(),
            KeyCode::Char('k') | KeyCode::Up => self.select_prev(),
            KeyCode::Char('b') => self.open_branch_popup().await,
            KeyCode::Char('r') => {
                let _ = self.cache.refresh().await;
                self.clamp_selection();
            }
            KeyCode::Enter => {
                // Future phase: switch to detail view.
            }
            _ => {}
        }
    }

    fn select_next(&mut self) {
        let len = self.cache.checkpoints().len();
        if len == 0 {
            return;
        }
        let i = self.list_state.selected().map_or(0, |i| {
            if i + 1 < len { i + 1 } else { i }
        });
        self.list_state.select(Some(i));
    }

    fn select_prev(&mut self) {
        let len = self.cache.checkpoints().len();
        if len == 0 {
            return;
        }
        let i = self
            .list_state
            .selected()
            .map_or(0, |i| i.saturating_sub(1));
        self.list_state.select(Some(i));
    }

    fn clamp_selection(&mut self) {
        let len = self.cache.checkpoints().len();
        if len == 0 {
            self.list_state.select(None);
        } else if let Some(i) = self.list_state.selected() {
            if i >= len {
                self.list_state.select(Some(len - 1));
            }
        }
    }

    async fn open_branch_popup(&mut self) {
        self.branches = list_branches().await.unwrap_or_default();
        let selected_index = self
            .branches
            .iter()
            .position(|b| b == &self.selected_branch)
            .unwrap_or(0);
        self.branch_list_state.select(Some(selected_index));
        self.branch_popup_open = true;
    }
}

use ratatui::Frame;
use ratatui::prelude::*;
use ratatui::widgets::{Block, Borders, List, ListItem};

use crate::app::App;

pub fn render(frame: &mut Frame, area: Rect, app: &mut App) {
    let checkpoints = app.cache.checkpoints();
    let commits = app.cache.commits();

    let items: Vec<ListItem> = checkpoints
        .iter()
        .map(|cp| {
            // Line 1: first commit subject or checkpoint_id fallback.
            let subject = cp
                .commit_hashes
                .first()
                .and_then(|hash| commits.iter().find(|c| &c.hash == hash || &c.short_hash == hash))
                .map_or_else(
                    || cp.checkpoint_id.clone(),
                    |c| c.subject.clone(),
                );

            // Line 2: details.
            let short_hash = cp
                .commit_hashes
                .first()
                .and_then(|hash| commits.iter().find(|c| &c.hash == hash || &c.short_hash == hash))
                .map_or_else(String::new, |c| c.short_hash.clone());

            let date_str = cp
                .sessions
                .first()
                .map_or_else(String::new, |s| format_relative_time(&s.created_at));

            let agent = cp
                .sessions
                .first()
                .map_or("unknown", |s| &s.agent);

            let (additions, deletions) = commit_stats(cp, commits);

            let files_count = cp.files_touched.len();

            let total_tokens = cp.token_usage.input_tokens + cp.token_usage.output_tokens;
            let token_display = format_tokens(total_tokens);

            let detail_line = format!(
                "  {short_hash}  {date_str}  {agent}  +{additions}/-{deletions}  {files_count} files  {token_display}",
            );

            ListItem::new(vec![
                Line::from(Span::raw(subject)),
                Line::from(Span::styled(
                    detail_line,
                    Style::default().fg(Color::DarkGray),
                )),
            ])
        })
        .collect();

    let title = format!(" Checkpoints [{}] ", app.selected_branch);
    let list = List::new(items)
        .block(Block::default().borders(Borders::ALL).title(title))
        .highlight_style(Style::default().bg(Color::DarkGray))
        .highlight_symbol("> ");

    frame.render_stateful_widget(list, area, &mut app.list_state);
}

fn commit_stats(
    cp: &mementor_lib::model::CheckpointMeta,
    commits: &[mementor_lib::git::log::CommitInfo],
) -> (usize, usize) {
    // Sum additions/deletions from commit diffs is not available in CommitInfo.
    // Use files_touched length as a proxy; actual diff stats would require
    // loading diffs which is lazy. For now, show file count only via the
    // checkpoint's commit count as a rough indicator.
    let _ = (cp, commits);
    (0, 0)
}

fn format_tokens(total: u64) -> String {
    if total >= 1_000_000 {
        let m = total as f64 / 1_000_000.0;
        format!("{m:.1}M tok")
    } else if total >= 1_000 {
        let k = total as f64 / 1_000.0;
        format!("{k:.1}K tok")
    } else {
        format!("{total} tok")
    }
}

fn format_relative_time(iso_str: &str) -> String {
    // Parse ISO 8601 timestamp and compute relative time.
    // Use jiff for parsing, falling back to raw string on failure.
    let Ok(timestamp) = iso_str.parse::<jiff::Timestamp>() else {
        return iso_str.to_owned();
    };
    let now = jiff::Timestamp::now();
    let span = timestamp.until(&now);
    let Ok(span) = span else {
        return iso_str.to_owned();
    };

    let total_seconds = span.get_seconds();
    let hours = total_seconds / 3600;
    let days = hours / 24;

    if days > 0 {
        format!("{days}d ago")
    } else if hours > 0 {
        format!("{hours}h ago")
    } else {
        let mins = total_seconds / 60;
        if mins > 0 {
            format!("{mins}m ago")
        } else {
            "just now".to_owned()
        }
    }
}

